const featuredProducts = h.featuredProducts ? products.filter((p: any) => p.featured) : products.slice(0, 6)
const newArrivals = products.filter((p: any) => p.new)

function AnimatedStat({ value, label }: { value: string; label: string }) {
  const [display, setDisplay] = useState("—")
  const ref = useRef<HTMLDivElement>(null)
  const [animated, setAnimated] = useState(false)

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting && !animated) {
          setAnimated(true)
          const target = parseInt(value.replace(/[^\d]/g, ""), 10) || 0
          if (target === 0) { setDisplay(value); return }
          let current = 0
          const step = Math.ceil(target / 30)
          const interval = setInterval(() => {
            current += step
            if (current >= target) { clearInterval(interval); setDisplay(value) }
            else setDisplay(current.toString())
          }, 40)
        }
      },
      { threshold: 0.5 }
    )
    if (ref.current) observer.observe(ref.current)
    return () => observer.disconnect()
  }, [value, animated])

  return (
    <div ref={ref} className="text-center">
      <div className="text-3xl font-bold text-primary sm:text-4xl transition-all duration-500">{display}</div>
      <div className="mt-1 text-sm font-medium text-muted-foreground">{label}</div>
    </div>
  )
}

