{"code": "from hermes_tools import terminal, write_file, read_file, search_files
import re, os

DST = "/root/fun4me-store"

# Fix blog page imports — they import @/components/* and @/content/es.json
blog_files = [
    f"{DST}/src/app/blog/[slug]/page.tsx",
    f"{DST}/src/app/blog/categoria/[category]/page.tsx",
    f"{DST}/src/app/blog/page.tsx",
]

for fp in blog_files:
    content = terminal(f"cat '{fp}'", timeout=5)['output']
    original = content

    # Fix @/components/... imports to point to vendor/ when component is in vendor/
    def fix_import(m):
        full_ref = m.group(1)
        # components already in store/ or ui/ stay as-is
        for prefix in ['ui/', 'store/', 'admin/', 'shared/', 'vendor/', 'animations/']:
            if full_ref.startswith(f'components/{prefix}'):
                return m.group(0)
        comp_name = full_ref.replace('components/', '')
        # Check if exists in vendor/
        if os.path.exists(f"{DST}/src/components/vendor/{comp_name}.tsx"):
            return f'@/components/vendor/{comp_name}'
        if os.path.exists(f"{DST}/src/components/store/{comp_name}.tsx"):
            return f'@/components/store/{comp_name}'
        return m.group(0)

    content = re.sub(r'@/(components/[^"\';\s)]+)', fix_import, content)

    if content != original:
        write_file(fp, content)
        print(f"Fixed {os.path.basename(fp)}")
    else:
        print(f"No changes needed in {os.path.basename(fp)}")"}

